import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Method;

public class CSVFormatTest {

    private enum TestEnum {
        VALUE1, VALUE2, VALUE3
    }

    @Test
    public void testWithHeader_withNullEnum_returnsSameFormatWithNullHeader() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader((Class<? extends Enum<?>>) null);
        String[] header = result.getHeader();
        assertNull(header);
    }

    @Test
    public void testWithHeader_withEnum_returnsFormatWithHeaderNames() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader(TestEnum.class);
        String[] header = result.getHeader();
        assertNotNull(header);
        assertEquals(TestEnum.values().length, header.length);
        for (int i = 0; i < TestEnum.values().length; i++) {
            assertEquals(TestEnum.values()[i].name(), header[i]);
        }
    }

    @Test
    public void testWithHeader_invokesWithHeaderArray() throws Exception {
        CSVFormat format = Mockito.spy(CSVFormat.DEFAULT);

        // Use reflection to get withHeader(Class) method
        Method withHeaderClassMethod = CSVFormat.class.getMethod("withHeader", Class.class);

        // Invoke withHeader(Class) on spy
        CSVFormat result = (CSVFormat) withHeaderClassMethod.invoke(format, TestEnum.class);

        // Verify that withHeader(String...) was called once with correct header names
        Mockito.verify(format).withHeader("VALUE1", "VALUE2", "VALUE3");
        assertNotNull(result);
    }
}
